export default App;

import React, { useCallback, useEffect, useRef, useState } from 'react';
import type { CanvasElement, Point, ArrowElement, NoteElement, AnalysisResult } from '../types';

interface TransformableElementProps {
  element: CanvasElement;
  isSelected: boolean;
  isMultiSelect: boolean;
  isOutpainting: boolean;
  zoom: number;
  onSelect: (id: string, shiftKey: boolean) => void;
  onUpdate: (element: CanvasElement, dragDelta?: Point) => void;
  onInteractionEnd: () => void;
  onContextMenu: (e: React.MouseEvent | React.TouchEvent, elementId: string) => void;
  onEditDrawing: (elementId: string) => void;
  t: (key: string) => string;
  language: 'en' | 'zh';
  analysisResults: Record<string, AnalysisResult>;
  analyzingElementId: string | null;
  onAnalyzeElement: (elementId: string) => void;
  onOptimizeNotePrompt: (elementId: string) => void;
  analysisVisibility: Record<string, boolean>;
  onToggleAnalysisVisibility: (elementId: string) => void;
  onClearAnalysis: (elementId: string) => void;
  onTranslateAnalysis: (elementId: string) => void;
  translatingElementId: string | null;
}

type Interaction = {
  type: 'drag' | 'resize' | 'rotate' | 'resize-arrow-start' | 'resize-arrow-end';
  startPoint: Point;
  startElement: CanvasElement;
  startAngle?: number;
  center?: Point;
} | null;

