      <path strokeLinecap="round" strokeLinejoin="round" d="M14.121 14.121a3 3 0 11-4.242-4.242 3 3 0 014.242 4.242zM12 12a3 3 0 00-3 3M17.59 5.337a10.03 10.03 0 012.35 6.663c-1.274 4.057-5.064 7-9.542 7-.847 0-1.673-.105-2.468-.303l-1.593-1.593" />
      <path strokeLinecap="round" strokeLinejoin="round" d="M3 3l18 18" />
