    const handleDragEnter = (e: DragEvent) => {
        preventDefaults(e);
        dragCounter.current++;
        if (e.dataTransfer?.items && e.dataTransfer.items.length > 0) {
            if (Array.from(e.dataTransfer.items).some(item => item.kind === 'file' && item.type.startsWith('image/'))) {
                 setIsDraggingOver(true);
