        selectedSet.has(el.id) ? { ...el, groupId: newGroupId } as CanvasElement : el
    ));
  }, [selectedElementIds, setElements, getSelectedGroupInfo.canGroup]);

  const ungroupElements = useCallback(() => {
    if (!getSelectedGroupInfo.canUngroup) return;

