        try {
            if (el.type === 'note') {
                await navigator.clipboard.writeText(el.content);
                return;
            } else if ((el.type === 'image' || el.type === 'drawing') && el.src) {
                const response = await fetch(el.src);
                const blob = await response.blob();
                await navigator.clipboard.write([
                    new ClipboardItem({
