             <div className="pt-2 border-t border-gray-100"><h2 className="text-xs font-bold text-gray-400 mb-2">{t('settings')}</h2><div className="grid grid-cols-2 gap-2"><button onClick={toggleLanguage} className="px-3 py-2 text-sm font-bold bg-gray-100 rounded-lg">{t('changeLanguage')}</button><button onClick={() => setPanelAlignment(p => p === 'left' ? 'right' : 'left')} className="px-3 py-2 text-sm font-bold bg-gray-100 rounded-lg">{panelAlignment === 'left' ? t('alignPanelRight') : t('alignPanelLeft')}</button></div></div>

