        )}

        {selectedElementIds.length > 0 && canChangeColor && (
            <div className="border-t border-gray-100 pt-3">
                <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider mb-2">{t('color')}</h2>
                <div className="grid grid-cols-8 gap-1">
                    {COLORS.map(color => (
                        <button key={color.name} onClick={() => handleColorChange(color.bg)} className={`w-6 h-6 rounded-md border border-black/5 ${color.bg} hover:scale-110 transition-transform`}/>
                    ))}
                </div>
            </div>
        )}

         <div className="flex flex-col gap-2 border-t border-gray-100 pt-3">
            <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-wider">{t('controls')}</h2>
            <div className="mb-1">
                <div className="w-full bg-gray-100 rounded-lg p-1 grid grid-cols-2 gap-1">
                    <button onClick={() => setInteractionMode('pan')} className={`px-2 py-1.5 text-xs font-bold rounded-md transition-all ${interactionMode === 'pan' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>{t('panMode')}</button>
                    <button onClick={() => setInteractionMode('select')} className={`px-2 py-1.5 text-xs font-bold rounded-md transition-all ${interactionMode === 'select' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>{t('selectMode')}</button>
                </div>
            </div>
            <div className="grid grid-cols-2 gap-2 mb-2">
                <button onClick={handleCopySelection} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-xs font-bold bg-white text-gray-700 rounded-lg border border-gray-200 hover:bg-gray-50 disabled:opacity-50 transition-all">
                    {t('copyToClipboard')}
