            <div className="grid grid-cols-2 gap-2">
                <button onClick={handleExportCanvas} className="px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-all">{t('export')}</button>
                <label className="cursor-pointer text-center px-2 py-2 text-xs font-bold bg-blue-50 text-blue-700 rounded-lg hover:bg-blue-100 transition-all">
