                    <input type="file" accept=".json" ref={importInputRef} className="hidden" onChange={handleImportCanvas} />
                </label>
                <button onClick={undo} disabled={!canUndo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('undo')}</button>
                <button onClick={redo} disabled={!canRedo} className="px-2 py-2 text-xs font-bold bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 disabled:opacity-30 transition-all">{t('redo')}</button>
                <button onClick={groupElements} disabled={!getSelectedGroupInfo.canGroup} className="px-2 py-2 text-xs font-bold bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 disabled:opacity-30 transition-all flex items-center justify-center gap-1">
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z"/></svg>
                    {t('group')}
                </button>
                <button onClick={ungroupElements} disabled={!getSelectedGroupInfo.canUngroup} className="px-2 py-2 text-xs font-bold bg-indigo-50 text-indigo-700 rounded-lg hover:bg-indigo-100 disabled:opacity-30 transition-all flex items-center justify-center gap-1">
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"/></svg>
                    {t('ungroup')}
                </button>
                <button onClick={bringToFront} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-[10px] font-bold bg-gray-800 text-white rounded-lg hover:bg-black disabled:opacity-30 transition-all truncate">{t('bringToFront')}</button>
                <button onClick={sendToBack} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-[10px] font-bold bg-gray-500 text-white rounded-lg hover:bg-gray-600 disabled:opacity-30 transition-all truncate">{t('sendToBack')}</button>
                <button onClick={deleteElement} disabled={selectedElementIds.length === 0} className="px-2 py-2 text-xs font-bold bg-red-50 text-red-600 rounded-lg hover:bg-red-100 disabled:opacity-30 transition-all col-span-1">{t('delete')}</button>
                <button onClick={resetView} className="px-2 py-2 text-xs font-bold bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-all col-span-1">{t('resetView')}</button>
            </div>
             <div className="pt-2 border-t border-gray-100"><h2 className="text-xs font-bold text-gray-400 mb-2">{t('settings')}</h2><div className="grid grid-cols-2 gap-2"><button onClick={toggleLanguage} className="px-3 py-2 text-sm font-bold bg-gray-100 rounded-lg">{t('changeLanguage')}</button><button onClick={() => setPanelAlignment(p => p === 'left' ? 'right' : 'left')} className="px-3 py-2 text-sm font-bold bg-gray-100 rounded-lg">{panelAlignment === 'left' ? t('alignPanelRight') : t('alignPanelLeft')}</button></div></div>

        </div>
      </div>

      <button
        onClick={() => setIsMenuCollapsed(!isMenuCollapsed)}
        className="absolute top-4 z-20 p-2.5 bg-white/90 backdrop-blur-md rounded-full shadow-xl border border-gray-200 hover:bg-gray-100 transition-all duration-300 ease-in-out"
        style={{ [panelAlignment]: isMenuCollapsed ? '1rem' : 'calc(1rem + 18rem + 0.5rem)' }}
      >
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-gray-700 transition-transform ${isMenuCollapsed ? (panelAlignment === 'left' ? 'rotate-180' : '') : (panelAlignment === 'left' ? '' : 'rotate-180')}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      <InfiniteCanvas 
        ref={canvasApiRef}
        elements={elements} 
        selectedElementIds={selectedElementIds}
        onSelectElement={handleSelectElement}
        onMarqueeSelect={handleMarqueeSelect}
        onUpdateElement={updateElements}
        onUpdateMultipleElements={updateMultipleElements}
        onInteractionEnd={handleInteractionEnd}
        setResetViewCallback={getResetViewCallback} 
        onGenerate={handleGenerate}
        onContextMenu={handleContextMenu}
        onEditDrawing={handleEditDrawing}
        onMouseMove={handleCanvasMouseMove}
        onViewportChange={handleViewportChange}
        imageStyle={imageStyle}
        onSetImageStyle={setImageStyle}
        imageAspectRatio={imageAspectRatio}
        onSetImageAspectRatio={setImageAspectRatio}
        outpaintingState={outpaintingState}
        onUpdateOutpaintingFrame={handleUpdateOutpaintingFrame}
        onCancelOutpainting={handleCancelOutpainting}
        onOutpaintingGenerate={handleOutpaintingGenerate}
        onAutoPromptGenerate={handleAutoPromptGenerate}
        interactionMode={interactionMode}
        t={t}
        language={language}
        analysisResults={analysisResults}
        analyzingElementId={analyzingElementId}
        onAnalyzeElement={handleAnalyzeElement}
        onOptimizeNotePrompt={handleOptimizeNotePrompt}
        analysisVisibility={analysisVisibility}
        onToggleAnalysisVisibility={handleToggleAnalysisVisibility}
        onClearAnalysis={handleClearAnalysis}
        onTranslateAnalysis={handleTranslateAnalysis}
        translatingElementId={translatingElementId}
      />

      <Minimap elements={elements} viewport={viewport} onPanTo={handlePanTo} onZoomIn={handleZoomIn} onZoomOut={handleZoomOut} />

      {isGenerating && (
        <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center text-white">
            <div className="relative">
                <div className="w-16 h-16 border-4 border-blue-400/20 border-t-blue-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center text-2xl">🍌</div>
            </div>
            <p className="mt-6 text-xl font-black tracking-widest uppercase">{t('generatingImages')}</p>
            <p className="text-blue-300 animate-pulse">{t('thisMayTakeAMoment')}</p>
        </div>
      )}

      {generatedImages && generatedImages.length > 0 && (
        <div className="absolute inset-0 z-50 bg-black/80 backdrop-blur-md flex items-center justify-center p-4" onClick={() => setGeneratedImages(null)}>
          <div className="bg-white rounded-3xl shadow-2xl p-6 max-w-5xl w-full max-h-[90vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black text-gray-800">{t('chooseAnImage')}</h2>
              <button onClick={() => setGeneratedImages(null)} className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 overflow-y-auto pr-2 custom-scrollbar">
              {generatedImages.map((imgSrc, index) => (
                <div key={index} className="group relative bg-gray-50 rounded-2xl overflow-hidden border border-gray-100 flex flex-col">
                  <img src={imgSrc} className="w-full h-auto object-contain max-h-[50vh]" />
                  <div className="p-3 flex gap-3 bg-white border-t">
                    <button onClick={() => addGeneratedImageToCanvas(imgSrc)} className="flex-1 py-2.5 bg-green-500 text-white font-bold rounded-md hover:bg-green-600 transition-all shadow-sm">{t('addToCanvas')}</button>
                    <button onClick={() => downloadGeneratedImage(imgSrc)} className="flex-1 py-2.5 bg-blue-600 text-white font-bold rounded-md hover:bg-blue-700 transition-all shadow-sm">{t('download')}</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {editingDrawing && <DrawingModal element={editingDrawing} onSave={handleSaveDrawing} onClose={() => setEditingDrawing(null)} t={t} />}
      {editingImage && <ImageEditModal element={editingImage} onSave={handleSaveImageEdit} onClose={() => setEditingImage(null)} ai={getAi()} t={t} />}
      {croppingImage && <CropModal element={croppingImage} onSave={handleSaveCrop} onClose={() => setCroppingImage(null)} t={t} />}

      {contextMenu && (
        <ContextMenu
          menuData={contextMenu}
          onClose={() => setContextMenu(null)}
          actions={{
            addNote, addArrow, addDrawing, editDrawing: handleEditDrawing,
            startImageEdit: handleStartImageEdit, startOutpainting: handleStartOutpainting,
            startCrop: handleStartCrop,
            addImage: triggerImageUpload, deleteElement, bringToFront, sendToBack,
            changeColor: handleColorChange, downloadImage, duplicateElement,
            toggleLanguage, groupElements, ungroupElements,
            copyToClipboard: handleCopyToClipboard,
            tidyUp: tidyUpSelected,
          }}
          canChangeColor={canChangeColor}
          canGroup={getSelectedGroupInfo.canGroup}
          canUngroup={getSelectedGroupInfo.canUngroup}
          selectedCount={selectedElementIds.length}
          elementType={contextMenuElement?.type || null}
          t={t}
        />
      )}

      {isDraggingOver && (
        <div className="absolute inset-0 z-[100] bg-blue-600/20 backdrop-blur-sm flex items-center justify-center pointer-events-none border-8 border-dashed border-blue-500 m-4 rounded-3xl">
          <div className="bg-white p-10 rounded-3xl shadow-2xl text-center">
            <span className="text-6xl mb-4 block">📸</span>
            <p className="text-2xl font-black text-gray-800">Drop to import images</p>
          </div>
        </div>
      )}
    </main>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ImageElement, Point } from '../types';

interface CropModalProps {
  element: ImageElement;
  onSave: (elementId: string, dataUrl: string, newWidth: number, newHeight: number) => void;
  onClose: () => void;
  t: (key: string) => string;
}

export const CropModal: React.FC<CropModalProps> = ({ element, onSave, onClose, t }) => {
  const [imgLoaded, setImgLoaded] = useState(false);
  const [containerSize, setContainerSize] = useState({ width: 0, height: 0 });
  const [cropRect, setCropRect] = useState({ x: 10, y: 10, width: 80, height: 80 }); // Percentages
  const [aspectRatio, setAspectRatio] = useState<number | null>(null); // null means Free
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const isDragging = useRef<string | null>(null);
  const startPos = useRef<Point>({ x: 0, y: 0 });

  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        setContainerSize({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight,
        });
      }
    };
    window.addEventListener('resize', updateSize);
    updateSize();
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  const handleImgLoad = () => {
      setImgLoaded(true);
      // Initialize with Free aspect
      setAspectRatio(null);
  };

  const applyAspectRatio = (ratio: number | null) => {
      setAspectRatio(ratio);
      if (ratio === null || !imgRef.current) return;

      const imgWidth = imgRef.current.naturalWidth;
      const imgHeight = imgRef.current.naturalHeight;
      const imageRatio = imgWidth / imgHeight;

      // Calculate target dimensions in percentages
      // Target visual ratio: ratio
      // Visual W / Visual H = ratio
      // (w_pct * imgW) / (h_pct * imgH) = ratio
      // w_pct / h_pct = ratio * (imgH / imgW) = ratio / imageRatio

      const targetPercentRatio = ratio / imageRatio;

      let newWidth = cropRect.width;
      let newHeight = newWidth / targetPercentRatio;

      if (newHeight > 100) {
          newHeight = 80; // Reset to reasonable default if it overflows heavily
          newWidth = newHeight * targetPercentRatio;
      }

      // Center the new rect
      let newX = cropRect.x + (cropRect.width - newWidth) / 2;
      let newY = cropRect.y + (cropRect.height - newHeight) / 2;

      // Clamp to bounds
      if (newX < 0) newX = 0;
      if (newY < 0) newY = 0;
      if (newX + newWidth > 100) newX = 100 - newWidth;
      if (newY + newHeight > 100) newY = 100 - newHeight;

      setCropRect({ x: newX, y: newY, width: newWidth, height: newHeight });
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent, type: string) => {
    e.stopPropagation();
    const pos = 'touches' in e ? e.touches[0] : e;
    isDragging.current = type;
    startPos.current = { x: pos.clientX, y: pos.clientY };
  };

  const handleMove = useCallback((e: MouseEvent | TouchEvent) => {
    if (!isDragging.current || !containerRef.current) return;
    const pos = 'touches' in e ? e.touches[0] : e;

    // Calculate movement in percentages relative to container
    const dx = ((pos.clientX - startPos.current.x) / containerSize.width) * 100;
    const dy = ((pos.clientY - startPos.current.y) / containerSize.height) * 100;

    setCropRect(prev => {
      let { x, y, width, height } = prev;
      const minSize = 5;

      if (isDragging.current === 'move') {
        x = Math.max(0, Math.min(100 - width, x + dx));
        y = Math.max(0, Math.min(100 - height, y + dy));
      } else {
        // Resizing logic
        let newX = x;
        let newY = y;
        let newWidth = width;
        let newHeight = height;

        // Apply raw changes first based on handle
        if (isDragging.current === 'nw') {
            newWidth = width - dx;
            newHeight = height - dy;
            newX = x + dx;
            newY = y + dy;
        } else if (isDragging.current === 'ne') {
            newWidth = width + dx;
            newHeight = height - dy;
            newY = y + dy;
        } else if (isDragging.current === 'sw') {
            newWidth = width - dx;
            newHeight = height + dy;
            newX = x + dx;
        } else if (isDragging.current === 'se') {
            newWidth = width + dx;
            newHeight = height + dy;
        }

        // Apply aspect ratio constraints if set
        if (aspectRatio !== null && imgRef.current) {
             const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
             const targetPercentRatio = aspectRatio / imageRatio;

             // When enforcing ratio, dragging a corner usually follows the dominant axis or the mouse projection.
             // Simplest approach: use width as driver if horizontally moving more, or height if vertically.
             // Or just take the newWidth and force newHeight, then check bounds.

             // Let's rely on width for SE/SW and force height, checking bounds.
             // For NW/NE, since Y is changing (top anchor), it's trickier.

             if (isDragging.current === 'se' || isDragging.current === 'sw') {
                 newHeight = newWidth / targetPercentRatio;
             } else if (isDragging.current === 'ne' || isDragging.current === 'nw') {
                 // For top handles, height change pulls the top edge. 
                 // We should probably preserve the bottom edge fixed.
                 // Actually, let's just force height based on width again for consistency, 
                 // but we need to adjust Y so bottom edge stays fixed.
                 const oldBottom = y + height;
                 newHeight = newWidth / targetPercentRatio;
                 newY = oldBottom - newHeight;
             }
        }

        // Check boundaries and min size
        // 1. Min size check
        if (newWidth < minSize) {
             newWidth = minSize;
             if (isDragging.current === 'nw' || isDragging.current === 'sw') newX = x + width - minSize; 
             if (aspectRatio !== null && imgRef.current) {
                const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                newHeight = newWidth / (aspectRatio / imageRatio);
                if (isDragging.current === 'nw' || isDragging.current === 'ne') newY = y + height - newHeight;
             }
        }
        if (newHeight < minSize) {
             newHeight = minSize;
             if (isDragging.current === 'nw' || isDragging.current === 'ne') newY = y + height - minSize;
             if (aspectRatio !== null && imgRef.current) {
                 // If height was constrained, update width
                const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                newWidth = newHeight * (aspectRatio / imageRatio);
                if (isDragging.current === 'nw' || isDragging.current === 'sw') newX = x + width - newWidth;
             }
        }

        // 2. Boundary Check (0-100)
        // This is complex with aspect ratio because constraining one side might break the other side's bound.
        // We will do a basic clamp and if that breaks aspect, we shrink the other side too.

        if (newX < 0) {
            newWidth += newX; // shrink width by overflow amount
            newX = 0;
            if (aspectRatio !== null && imgRef.current) {
                const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                const oldH = newHeight;
                newHeight = newWidth / (aspectRatio / imageRatio);
                // Adjust Y if top is moving
                if (isDragging.current === 'nw') newY += (oldH - newHeight); 
                // If NE, Y moves (top edge), but since we shrunk width (pulled right edge left?), actually if X < 0 on NE, we don't care because NE doesn't move X left. 
                // Wait, NE moves right edge. X stays.
            }
        }
        if (newY < 0) {
            newHeight += newY;
            newY = 0;
            if (aspectRatio !== null && imgRef.current) {
                const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                const oldW = newWidth;
                newWidth = newHeight * (aspectRatio / imageRatio);
                if (isDragging.current === 'nw') newX += (oldW - newWidth);
                if (isDragging.current === 'ne') { /* X stays same? No, NE moves Right edge. If we shrink height, we shrink width. Width shrinks from right? Yes, so X stays. */ }
            }
        }

        if (newX + newWidth > 100) {
            newWidth = 100 - newX;
            if (aspectRatio !== null && imgRef.current) {
                 const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                 const oldH = newHeight;
                 newHeight = newWidth / (aspectRatio / imageRatio);
                 if (isDragging.current === 'ne') newY += (oldH - newHeight);
            }
        }
        if (newY + newHeight > 100) {
            newHeight = 100 - newY;
            if (aspectRatio !== null && imgRef.current) {
                const imageRatio = imgRef.current.naturalWidth / imgRef.current.naturalHeight;
                const oldW = newWidth;
                newWidth = newHeight * (aspectRatio / imageRatio);
                if (isDragging.current === 'sw') newX += (oldW - newWidth);
            }
        }

        width = newWidth;
        height = newHeight;
        x = newX;
        y = newY;
      }

      startPos.current = { x: pos.clientX, y: pos.clientY };
      return { x, y, width, height };
    });
  }, [containerSize, aspectRatio]);

  const handleEnd = useCallback(() => {
    isDragging.current = null;
  }, []);

  useEffect(() => {
    window.addEventListener('mousemove', handleMove);
    window.addEventListener('mouseup', handleEnd);
    window.addEventListener('touchmove', handleMove);
    window.addEventListener('touchend', handleEnd);
    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleEnd);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleEnd);
    };
  }, [handleMove, handleEnd]);

  const handleSave = () => {
    if (!imgRef.current) return;
    const img = imgRef.current;
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const sourceX = (cropRect.x / 100) * img.naturalWidth;
    const sourceY = (cropRect.y / 100) * img.naturalHeight;
    const sourceWidth = (cropRect.width / 100) * img.naturalWidth;
    const sourceHeight = (cropRect.height / 100) * img.naturalHeight;

    canvas.width = sourceWidth;
    canvas.height = sourceHeight;

    ctx.drawImage(
      img,
      sourceX, sourceY, sourceWidth, sourceHeight,
      0, 0, sourceWidth, sourceHeight
    );

    const croppedDataUrl = canvas.toDataURL('image/png');
    // Maintain scale: Calculate new display size based on the crop ratio
    const newWidth = element.width * (cropRect.width / 100);
    const newHeight = element.height * (cropRect.height / 100);

    onSave(element.id, croppedDataUrl, newWidth, newHeight);
  };

  const Ratios = [
      { label: t('free'), value: null },
      { label: '1:1', value: 1 },
      { label: '4:3', value: 4/3 },
      { label: '16:9', value: 16/9 },
  ];

  return (
    <div className="fixed inset-0 z-[100] bg-black/90 flex flex-col items-center justify-center p-4 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
        <div className="p-6 border-b flex justify-between items-center bg-[#0F172A] text-white">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
            {t('cropImage')}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-400 hover:text-white">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        <div className="flex-grow bg-black relative p-8 flex items-center justify-center overflow-hidden min-h-[300px]">
          <div ref={containerRef} className="relative inline-block shadow-2xl">
            <img 
              ref={imgRef}
              src={element.src} 
              alt="To Crop" 
              className="max-w-full max-h-[60vh] block select-none pointer-events-none" 
              onLoad={handleImgLoad}
            />
            {imgLoaded && (
              <>
                {/* Dimmed Overlay */}
                <div className="absolute inset-0 bg-black/60 pointer-events-none"></div>

                {/* Crop Area */}
                <div 
                  className="absolute border-2 border-white shadow-[0_0_0_9999px_rgba(0,0,0,0.6)] cursor-move"
                  style={{
                    left: `${cropRect.x}%`,
                    top: `${cropRect.y}%`,
                    width: `${cropRect.width}%`,
                    height: `${cropRect.height}%`,
                  }}
                  onMouseDown={e => handleStart(e, 'move')}
                  onTouchStart={e => handleStart(e, 'move')}
                >
                    {/* Handles - Only corners if aspect ratio is locked? No, keep corners always. */}
                    <div className="absolute -top-1.5 -left-1.5 w-4 h-4 bg-white border border-gray-400 rounded-full cursor-nw-resize shadow-sm" onMouseDown={e => handleStart(e, 'nw')} onTouchStart={e => handleStart(e, 'nw')}></div>
                    <div className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-white border border-gray-400 rounded-full cursor-ne-resize shadow-sm" onMouseDown={e => handleStart(e, 'ne')} onTouchStart={e => handleStart(e, 'ne')}></div>
                    <div className="absolute -bottom-1.5 -left-1.5 w-4 h-4 bg-white border border-gray-400 rounded-full cursor-sw-resize shadow-sm" onMouseDown={e => handleStart(e, 'sw')} onTouchStart={e => handleStart(e, 'sw')}></div>
                    <div className="absolute -bottom-1.5 -right-1.5 w-4 h-4 bg-white border border-gray-400 rounded-full cursor-se-resize shadow-sm" onMouseDown={e => handleStart(e, 'se')} onTouchStart={e => handleStart(e, 'se')}></div>

                    {/* Grid lines */}
                    <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-40">
                        <div className="border-r border-white/80"></div>
                        <div className="border-r border-white/80"></div>
                        <div></div>
                        <div className="border-t border-white/80 col-span-3"></div>
                        <div className="border-t border-white/80 col-span-3"></div>
                    </div>
                </div>
              </>
            )}
          </div>
        </div>

        <div className="p-4 border-t border-gray-800 bg-[#0F172A] flex justify-between items-center gap-3">
          <div className="flex items-center gap-1 bg-gray-800 p-1 rounded-lg">
              {Ratios.map(r => (
                  <button
                    key={r.label}
                    onClick={() => applyAspectRatio(r.value)}
                    className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${aspectRatio === r.value ? 'bg-blue-600 text-white shadow-sm' : 'text-gray-400 hover:text-white hover:bg-gray-700'}`}
                  >
                      {r.label}
                  </button>
              ))}
          </div>
          <div className="flex gap-2">
            <button onClick={onClose} className="px-4 py-2 text-sm font-medium bg-gray-700 text-gray-200 rounded-lg hover:bg-gray-600 transition-all">{t('cancel')}</button>
            <button onClick={handleSave} className="px-5 py-2 text-sm font-bold bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-900/20 transition-all flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                {t('saveCrop')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

