                                transform: `translate(-50%, -50%)`,
                            }}
                            onMouseDown={(e) => handleGroupInteractionStart(e, 'group-resize')}
                            onTouchStart={(e) => handleGroupInteractionStart(e, 'group-resize')}
                        />
