InfiniteCanvas.displayName = "InfiniteCanvas";

const startDrawing = (e: React.MouseEvent) => {
  if (previewImageSrc) return;

  // Support Panning: Middle Mouse Button (1) OR (Left Click (0) + Spacebar)
  if (e.button === 1 || (e.button === 0 && isSpacebarPressed)) {
      e.preventDefault();
      setIsPanning(true);
      panStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
      return;
  }

  // Drawing only allows Left Click (0)
  if (e.button !== 0) return;

  const point = getCanvasPoint(e);
  if (!point) return;

  setIsDrawing(true);
  strokePointsRef.current = [point];
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { ImageElement, Point } from '../types';

interface ImageEditModalProps {
  element: ImageElement;
  onSave: (elementId: string, newSrc: string) => void;
  onClose: () => void;
  ai: GoogleGenAI | null;
  t: (key: string) => string;
}

export const ImageEditModal: React.FC<ImageEditModalProps> = ({ element, onSave, onClose, ai, t }) => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [previewImageSrc, setPreviewImageSrc] = useState<string | null>(null);

  // Canvas & Interaction State
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [pan, setPan] = useState<Point>({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [isPanning, setIsPanning] = useState(false);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(20);
  const [isSpacebarPressed, setIsSpacebarPressed] = useState(false);

  const panStartRef = useRef<Point>({ x: 0, y: 0 });
  const strokePointsRef = useRef<Point[]>([]);
  const maskCanvasRef = useRef<HTMLCanvasElement | null>(null);

  // Initialize Mask Canvas
  useEffect(() => {
    if (!maskCanvasRef.current) {
        const c = document.createElement('canvas');
        c.width = element.width;
        c.height = element.height;
        maskCanvasRef.current = c;
    }
  }, [element.width, element.height]);

  // Handle Spacebar for Panning
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (e.code === 'Space') setIsSpacebarPressed(true);
    };
    const handleKeyUp = (e: KeyboardEvent) => {
        if (e.code === 'Space') setIsSpacebarPressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
        window.removeEventListener('keydown', handleKeyDown);
        window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const getCanvasPoint = (e: React.MouseEvent | React.TouchEvent): Point | null => {
    const canvas = canvasRef.current;
    if (!canvas) return null;
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    return {
        x: (clientX - rect.left) * scaleX,
        y: (clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    if (previewImageSrc) return;

    // Support Panning: Middle Mouse Button (1) OR (Left Click (0) + Spacebar)
    if (e.button === 1 || (e.button === 0 && isSpacebarPressed)) {
        e.preventDefault();
        setIsPanning(true);
        panStartRef.current = { x: e.clientX - pan.x, y: e.clientY - pan.y };
        return;
    }

    // Drawing only allows Left Click (0)
    if (e.button !== 0) return;

    const point = getCanvasPoint(e);
    if (!point) return;

    setIsDrawing(true);
    strokePointsRef.current = [point];

    // Start Path on Mask Context
    const ctx = maskCanvasRef.current?.getContext('2d');
    if (ctx) {
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.strokeStyle = 'rgba(255, 0, 0, 0.5)'; // Red semi-transparent mask
        ctx.lineWidth = brushSize;
        ctx.beginPath();
        ctx.moveTo(point.x, point.y);
    }
  };

  const draw = (e: React.MouseEvent) => {
    if (isPanning) {
        setPan({ x: e.clientX - panStartRef.current.x, y: e.clientY - panStartRef.current.y });
        return;
    }

    if (!isDrawing) return;

    const point = getCanvasPoint(e);
    if (!point) return;

    strokePointsRef.current.push(point);

    const ctx = maskCanvasRef.current?.getContext('2d');
    if (ctx) {
        ctx.lineTo(point.x, point.y);
        ctx.stroke();
        requestAnimationFrame(renderCanvas);
    }
  };

  const stopDrawing = () => {
    setIsPanning(false);
    if (isDrawing) {
        setIsDrawing(false);
        const ctx = maskCanvasRef.current?.getContext('2d');
        ctx?.closePath();
    }
  };

  const clearMask = () => {
      const ctx = maskCanvasRef.current?.getContext('2d');
      if (ctx && maskCanvasRef.current) {
          ctx.clearRect(0, 0, maskCanvasRef.current.width, maskCanvasRef.current.height);
          renderCanvas();
      }
  };

  const renderCanvas = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Image
    const img = new Image();
    img.src = previewImageSrc || element.src;

    if (img.complete) {
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    } else {
        img.onload = () => ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    }

    // Draw Mask Overlay
    if (maskCanvasRef.current && !previewImageSrc) {
        ctx.drawImage(maskCanvasRef.current, 0, 0, canvas.width, canvas.height);
    }

  }, [element.src, previewImageSrc]);

  useEffect(() => {
      // Initial render
      const img = new Image();
      img.src = element.src;
      img.onload = renderCanvas;
  }, [renderCanvas, element.src]);

  const handleGenerate = async () => {
    if (!ai) return;
    setIsGenerating(true);
    try {
        const [header, data] = element.src.split(',');
        const mimeType = header.match(/data:(.*);base64/)?.[1] || 'image/png';

        const parts: any[] = [
            { inlineData: { data, mimeType } },
            { text: prompt }
        ];

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts }
        });

        const resultPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (resultPart?.inlineData) {
             const newSrc = `data:${resultPart.inlineData.mimeType};base64,${resultPart.inlineData.data}`;
             setPreviewImageSrc(newSrc);
        } else {
            alert("No image returned");
        }

    } catch (e) {
        console.error(e);
        alert("Generation failed");
    } finally {
        setIsGenerating(false);
    }
  };

  const handleApply = () => {
      if (previewImageSrc) {
          onSave(element.id, previewImageSrc);
      }
  };

  const handleDiscard = () => {
      setPreviewImageSrc(null);
  };

  // Wheel zoom
  const handleWheel = (e: React.WheelEvent) => {
      e.stopPropagation();
      setZoom(z => Math.max(0.1, Math.min(5, z - e.deltaY * 0.001)));
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/90 flex flex-col items-center justify-center p-4" onClick={onClose}>
        <div className="bg-white rounded-xl overflow-hidden w-full max-w-5xl h-[85vh] flex flex-col" onClick={e => e.stopPropagation()}>
            {/* Header */}
            <div className="bg-gray-100 p-4 flex justify-between items-center border-b">
                <h3 className="font-bold text-lg">{t('imageEdit')}</h3>
                <button onClick={onClose} className="text-gray-500 hover:text-black">&times;</button>
            </div>

            {/* Main Area */}
            <div className="flex-1 relative bg-gray-50 overflow-hidden flex items-center justify-center" onWheel={handleWheel}>
                 <div 
                    style={{ 
                        transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
                        transformOrigin: 'center',
                        cursor: isSpacebarPressed || isPanning ? 'grab' : 'crosshair'
                    }}
                 >
                     <canvas 
                        ref={canvasRef}
                        width={element.width}
                        height={element.height}
                        onMouseDown={startDrawing}
                        onMouseMove={draw}
                        onMouseUp={stopDrawing}
                        onMouseLeave={stopDrawing}
                        className="shadow-lg bg-white"
                     />
                 </div>

                 {/* Floating Controls for Zoom/Reset */}
                 <div className="absolute bottom-4 left-4 bg-white/90 p-2 rounded shadow flex gap-2">
                     <button onClick={() => setZoom(z => Math.max(0.1, z - 0.1))}>-</button>
                     <span>{Math.round(zoom * 100)}%</span>
                     <button onClick={() => setZoom(z => Math.min(5, z + 0.1))}>+</button>
                     <button onClick={() => { setZoom(1); setPan({x:0,y:0}); }}>{t('reset')}</button>
                 </div>
            </div>

            {/* Toolbar */}
            <div className="bg-white p-4 border-t flex flex-col gap-4">
                {!previewImageSrc ? (
                    <>
                        <div className="flex gap-4 items-center">
                            <div className="flex-1">
                                <input 
                                    type="text" 
                                    value={prompt} 
                                    onChange={e => setPrompt(e.target.value)}
                                    placeholder={t('describeYourEdit')}
                                    className="w-full border rounded px-3 py-2"
                                />
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="text-sm">{t('brushSize')}</span>
                                <input 
                                    type="range" 
                                    min="1" max="50" 
                                    value={brushSize} 
                                    onChange={e => setBrushSize(Number(e.target.value))}
                                />
                                <button onClick={clearMask} className="text-sm text-red-500 hover:underline">{t('clearMask')}</button>
                            </div>
                        </div>
                        <div className="flex justify-end gap-2">
                            <button onClick={onClose} className="px-4 py-2 rounded border hover:bg-gray-50">{t('cancel')}</button>
                            <button 
                                onClick={handleGenerate} 
                                disabled={isGenerating || !prompt.trim()}
                                className="px-4 py-2 rounded bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-50"
                            >
                                {isGenerating ? t('generatingImages') : t('generate')}
                            </button>
                        </div>
                    </>
                ) : (
                    <div className="flex justify-between items-center">
                        <span className="font-bold text-green-600">{t('previewOfYourEdit')}</span>
                        <div className="flex gap-2">
                            <button onClick={handleDiscard} className="px-4 py-2 rounded border border-red-200 text-red-600 hover:bg-red-50">{t('discard')}</button>
                            <button onClick={handleApply} className="px-4 py-2 rounded bg-green-600 text-white hover:bg-green-700">{t('applyAndContinue')}</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};
